body:
A:
```mlir
  firrtl.circuit "Top" {
    firrtl.module private @Bar(out %b: !firrtl.uint<1>) {
      %0 = firrtl.wire : !firrtl.uint<1>
      %c1_ui1 = firrtl.constant 1 : !firrtl.uint<1>
      firrtl.strictconnect %0, %c1_ui1 : !firrtl.uint<1>
      %1 = firrtl.xor %0, %c1_ui1 : (!firrtl.uint<1>, !firrtl.uint<1>) -> !firrtl.uint<1>
      firrtl.strictconnect %b, %1 : !firrtl.uint<1>
    }
    firrtl.module @Top(out %b: !firrtl.uint<1>) {
      %b_out = firrtl.instance bar @Bar(out b: !firrtl.uint<1>) 
      firrtl.strictconnect %b, %b_out : !firrtl.uint<1>
    }
  }
```

B: 
```mlir
   firrtl.circuit "Top" {
    firrtl.module private @Bar(out %b: !firrtl.uint<1>) {
      %0 = firrtl.wire : !firrtl.uint<1>
      %c1_ui1 = firrtl.constant 1 : !firrtl.uint<1>
      %1 = firrtl.xor %0, %c1_ui1 : (!firrtl.uint<1>, !firrtl.uint<1>) -> !firrtl.uint<1>
      firrtl.strictconnect %0, %c1_ui1 : !firrtl.uint<1>
      firrtl.strictconnect %b, %1 : !firrtl.uint<1>
    }
    firrtl.module @Top(out %b: !firrtl.uint<1>) {
      %b_out = firrtl.instance bar @Bar(out b: !firrtl.uint<1>) 
      firrtl.strictconnect %b, %b_out : !firrtl.uint<1>
    }
  }
```

The difference between A and B is the position of `%1`. Only B produces an optimal result:
`$ circt-opt -firrtl-imconstprop`.
A:
```mlir
  firrtl.circuit "Top" {
    firrtl.module private @Bar(out %b: !firrtl.uint<1>) {
      %c1_ui1 = firrtl.constant 1 : !firrtl.uint<1>
      %c1_ui1_0 = firrtl.constant 1 : !firrtl.uint<1>
      %0 = firrtl.xor %c1_ui1, %c1_ui1_0 : (!firrtl.uint<1>, !firrtl.uint<1>) -> !firrtl.uint<1>
      firrtl.strictconnect %b, %0 : !firrtl.uint<1>
    }
    firrtl.module @Top(out %b: !firrtl.uint<1>) {
      %bar_b = firrtl.instance bar @Bar(out b: !firrtl.uint<1>)
      firrtl.strictconnect %b, %bar_b : !firrtl.uint<1>
    }
  }
```
B:
```mlir
  firrtl.circuit "Top" {
    firrtl.module private @Bar(out %b: !firrtl.uint<1>) {
      %c0_ui1 = firrtl.constant 0 : !firrtl.uint<1>
      firrtl.strictconnect %b, %c0_ui1 : !firrtl.uint<1>
    }
    firrtl.module @Top(out %b: !firrtl.uint<1>) {
      %c0_ui1 = firrtl.constant 0 : !firrtl.uint<1>
      %bar_b = firrtl.instance bar @Bar(out b: !firrtl.uint<1>)
      firrtl.strictconnect %b, %c0_ui1 : !firrtl.uint<1>
    }
  }
```

This issue is caused by `unwritten` state.
